export default class{constructor(selector){this.pos={};this.el=selector;this.el instanceof Element||(this.el=this.searchElement(selector));if(!(this.el instanceof Element))return console.log("class position: Object not exist. (selector): ",selector);this.pos=this.getAllPositions()}get get(){return this}get top(){return this.pos.top}get topp(){return this.pos.topp}get bottom(){return this.pos.bottom}get left(){return this.pos.left}get leftp(){return this.pos.leftp}get right(){return this.pos.right}get width(){return this.pos.width}get height(){return this.pos.height}get x(){return this.pos.x}get y(){return this.pos.y}get xp(){return this.pos.xp}get yp(){return this.pos.yp}get padtop(){return this.pos.padtop}get padbottom(){return this.pos.padbottom}get padleft(){return this.pos.padleft}get padright(){return this.pos.padright}searchElement(selector){let sel=document.querySelector(selector);if(sel instanceof Element)return sel;const aS=[];for(const obj of document.body.querySelectorAll("*"))obj.shadowRoot&&aS.push(obj);for(const obj of aS){sel=obj.shadowRoot.querySelector(selector);if(sel)return sel}return null}getAllPositions(){let pos=this.el.getBoundingClientRect(),cstl=getComputedStyle(this.el),html=document.body;pos.xp=pos.x+Math.abs(html.scrollLeft);pos.yp=pos.y+Math.abs(html.scrollTop);pos.leftp=pos.left+Math.abs(html.scrollLeft);pos.topp=pos.top+Math.abs(html.scrollTop);pos.padtop=this.px2num(cstl.getPropertyValue("padding-top"));pos.padbottom=this.px2num(cstl.getPropertyValue("padding-bottom"));pos.padleft=this.px2num(cstl.getPropertyValue("padding-left"));pos.padright=this.px2num(cstl.getPropertyValue("padding-right"));pos.zIndex=cstl.getPropertyValue("z-index");pos.html={scrollTop:html.scrollTop,scrollLeft:html.scrollLeft,scrollWidth:html.scrollWidth,scrollHeight:html.scrollHeight,clientTop:html.clientTop,clientLeft:html.clientLeft,clientWidth:html.clientWidth,clientHeight:html.clientHeight,offsetTop:html.offsetTop,offsetLeft:html.offsetLeft,offsetWidth:html.offsetWidth,offsetHeight:html.offsetHeight};return pos}px2num(px){return new RegExp(/px$/).test(px)?parseFloat(px.replace("px")):px}}